export interface Question {
  id: number;
  question: string;
  options: string[];
  correct: number;
  explanation: string;
  difficulty: "beginner" | "intermediate" | "advanced";
  topic: string;
  learnLink: string;
}

export const allQuestions: Question[] = [
  // ── STOCKS ──────────────────────────────────────────
  { id: 1, question: "A company has a P/E ratio of 8 while its industry average is 22. Which interpretation is MOST accurate?", options: ["The stock is definitely undervalued and should be bought immediately", "The stock may be undervalued, but a low P/E can also signal declining earnings or structural problems", "The company is more profitable than its peers", "The stock is overvalued because P/E should always be above the industry average"], correct: 1, explanation: "A low P/E can indicate undervaluation, but it can also reflect legitimate concerns about the company's future — declining revenue, regulatory risk, or structural industry changes. Context matters more than the number alone.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 6, question: "If a stock's EPS grew 15% but its stock price fell 10% over the same period, what happened to the P/E ratio?", options: ["It increased significantly", "It stayed roughly the same", "It decreased by approximately 22%", "It cannot be determined without knowing the dividend yield"], correct: 2, explanation: "P/E = Price / EPS. If price drops 10% (multiply by 0.9) and EPS grows 15% (multiply by 1.15), new P/E = 0.9/1.15 ≈ 0.783 of the original — about a 22% decrease. The market is paying less per dollar of earnings.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 12, question: "During a bull market, which investor behavior typically leads to the WORST long-term outcomes?", options: ["Continuing regular index fund contributions", "Increasing allocation to bonds as prices rise", "Extrapolating recent gains and concentrating in the best-performing sector", "Rebalancing back to target allocation"], correct: 2, explanation: "Performance chasing — piling into whatever's been going up — is consistently the worst investor behavior. Sectors that dominate one period rarely lead the next. Rebalancing and staying diversified outperform chasing heat.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 21, question: "Two companies each have a $50 billion market cap. Company A has 500 million shares at $100; Company B has 5 billion shares at $10. Which statement is TRUE?", options: ["Company A is more valuable because its share price is higher", "Company B is riskier because its share price is lower", "Both companies have the same total equity value — share price alone is meaningless", "Company A is a better investment because it has fewer shares outstanding"], correct: 2, explanation: "Market cap (price × shares) is what matters, not share price. A $10 stock with 5 billion shares is worth exactly the same as a $100 stock with 500 million shares. Share price in isolation tells you nothing about value.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 22, question: "Which of the following is NOT a characteristic of a bear market?", options: ["A decline of 20% or more from recent highs", "Average duration of 9-12 months historically", "Investor capitulation and extreme pessimism near the bottom", "A guaranteed recession in the broader economy"], correct: 3, explanation: "While bear markets often coincide with recessions, not all do. The 2020 bear market lasted only 33 days and didn't produce a prolonged recession. Bear markets are defined by price decline, not economic activity.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 26, question: "A stock has a beta of 1.4 and the market drops 10%. Assuming the CAPM relationship holds, what is the stock's expected decline?", options: ["10%", "4%", "14%", "1.4%"], correct: 2, explanation: "Beta measures sensitivity to market movements. A beta of 1.4 means the stock is expected to move 1.4× the market's move. If the market drops 10%, the stock is expected to drop 14%. Higher beta = amplified moves in both directions.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 31, question: "Company X reports EPS of $5.00 but free cash flow per share of $2.50. What should a sophisticated investor conclude?", options: ["The company is twice as profitable as its cash flow suggests", "Earnings quality may be poor — large gap between reported earnings and actual cash generation warrants investigation", "Free cash flow is irrelevant if EPS is positive", "The stock is undervalued because EPS is higher than expected"], correct: 1, explanation: "A large gap between EPS and free cash flow per share is a red flag. It may indicate aggressive accounting, heavy capital expenditure needs, or working capital issues. Cash flow is harder to manipulate than earnings.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 32, question: "After a 2-for-1 stock split, an investor who owned 100 shares at $200 each now has:", options: ["200 shares at $200 each — their investment doubled", "100 shares at $100 each — their investment halved", "200 shares at $100 each — their total investment value is unchanged", "50 shares at $400 each — a reverse split occurred"], correct: 2, explanation: "In a 2-for-1 split, share count doubles and price halves. 100 shares × $200 = $20,000 before. 200 shares × $100 = $20,000 after. Total value is unchanged; the pie is just cut into more slices.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 33, question: "You place a limit order to buy XYZ at $48 when it's trading at $50. The stock drops to $47 then bounces to $52. What happened to your order?", options: ["It was never executed because you set it below market price", "It executed at $48 or better when the stock passed through that price on the way down", "It executed at $47 since that was the lowest price", "It executed at $52 because that's where the stock ended up"], correct: 1, explanation: "A buy limit order executes at your limit price or better when the market price reaches that level. When XYZ dropped through $48, the order filled at $48 or potentially lower. You wouldn't pay more than $48.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 34, question: "A short seller borrows 100 shares at $80 and the stock rises to $120. What is their unrealized loss, excluding fees?", options: ["$2,000", "$4,000", "$8,000", "$12,000"], correct: 1, explanation: "Short selling loss = (exit price - entry price) × shares. ($120 - $80) × 100 = $4,000 unrealized loss. Unlike long positions (max loss = 100%), short selling has theoretically unlimited loss potential since prices can rise indefinitely.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 35, question: "Which of these stocks would LEAST likely be classified as 'blue-chip'?", options: ["Johnson & Johnson (founded 1886, $400B+ market cap)", "A biotech startup with no revenue but a promising drug pipeline", "Procter & Gamble (60+ years of consecutive dividend increases)", "Microsoft (dominant market position, $2T+ market cap)"], correct: 1, explanation: "Blue-chip stocks are large, well-established companies with long histories of stable performance. A pre-revenue biotech startup, regardless of its potential, lacks the track record, size, and stability that define blue chips.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 36, question: "In the decade 2010-2020, growth stocks significantly outperformed value stocks. What does history suggest about the NEXT decade?", options: ["Growth will continue to outperform because technology is accelerating", "Value will definitely outperform because it's 'due'", "Neither style is guaranteed to lead — the dominant factor rotates and past performance doesn't predict future results", "Both will perform identically going forward"], correct: 2, explanation: "Growth vs. value leadership rotates over decades. Value dominated 2000-2010 after growth dominated the 1990s. No style permanently wins. Overweighting the recent winner (recency bias) typically hurts long-term returns.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 37, question: "An executive sells 50,000 shares of their own company through a pre-scheduled 10b5-1 plan filed 6 months ago. Is this insider trading?", options: ["Yes — all insider selling is illegal", "No — 10b5-1 plans are pre-scheduled when the insider has no material non-public information, making the trade legal", "It depends on whether the stock price went up or down after the sale", "Only if the executive is the CEO"], correct: 1, explanation: "10b5-1 plans allow insiders to set up pre-scheduled trades during periods when they have no material non-public information. This creates a legal safe harbor. Illegal insider trading requires trading on MNPI — information not yet available to the public.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 38, question: "A company's free cash flow yield is 8% and its dividend yield is 2%. What does this gap primarily indicate?", options: ["The company is in financial distress", "The company retains significant cash flow for reinvestment, buybacks, or debt reduction beyond dividends", "The dividend is about to be cut", "The company's earnings are declining"], correct: 1, explanation: "An FCF yield well above the dividend yield means the company generates much more cash than it pays out. The excess can fund growth, share buybacks, debt repayment, or future dividend increases — it signals financial strength, not weakness.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },

  // ── ETFs ──────────────────────────────────────────
  { id: 2, question: "An ETF tracking the S&P 500 has an expense ratio of 0.03%. On a $100,000 investment held for 30 years at 10% annual returns, approximately how much do you pay in total fees?", options: ["$900", "$3,000", "$5,200", "$15,000"], correct: 2, explanation: "At 0.03%, annual fees start at ~$30 and grow as the portfolio grows. Over 30 years with compound growth, total cumulative fees are roughly $5,200. This is dramatically less than an active fund charging 1% (which would cost ~$170,000).", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 13, question: "Fund A has an expense ratio of 0.50% and Fund B has 0.05%. Both earn 8% gross returns on a $100,000 investment over 25 years. How much MORE does Fund A cost you?", options: ["About $11,250", "About $38,000", "About $72,000", "About $120,000"], correct: 2, explanation: "Fund A (7.5% net): ~$596K. Fund B (7.95% net): ~$668K. Difference: ~$72,000. A 0.45% fee difference costs you over 70% of your original investment over 25 years. Expense ratios compound against you just like returns compound for you.", difficulty: "advanced", topic: "etfs", learnLink: "etfs" },
  { id: 24, question: "You're comparing two S&P 500 ETFs with identical expense ratios. Which factor should you evaluate NEXT?", options: ["Which has the cooler ticker symbol", "Tracking error, bid-ask spread, and daily trading volume (liquidity)", "Which one was launched more recently", "Which brokerage advertises it more"], correct: 1, explanation: "After matching expense ratios, differentiation comes from tracking error (how closely it matches the index), bid-ask spread (trading cost), and liquidity (ease of buying/selling). These are the real cost differences between similar ETFs.", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 30, question: "An index ETF has a tracking error of 0.15%. What does this mean in practice?", options: ["The ETF's returns deviate from its benchmark by an average of 0.15% per year", "The ETF charges 0.15% in fees", "The ETF's price is 0.15% below its NAV", "The ETF holds 0.15% of the index in cash"], correct: 0, explanation: "Tracking error measures the standard deviation of the difference between the ETF's returns and its benchmark's returns. A 0.15% tracking error is quite good and indicates the ETF closely mirrors the index.", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 39, question: "Which is a key tax advantage that ETFs have over mutual funds?", options: ["ETFs don't pay any taxes", "ETFs use an in-kind creation/redemption mechanism that minimizes capital gains distributions to shareholders", "ETF dividends are always tax-free", "ETFs are not subject to wash sale rules"], correct: 1, explanation: "ETFs' unique structure allows authorized participants to exchange baskets of stocks for ETF shares (and vice versa) without triggering taxable events. This means ETFs rarely distribute capital gains, unlike mutual funds that must distribute gains when they sell holdings.", difficulty: "advanced", topic: "etfs", learnLink: "etfs" },
  { id: 40, question: "A sector ETF focused on energy has returned 45% this year. What is the PRIMARY risk of buying it now?", options: ["Sector ETFs always lose money", "Concentrated sector exposure lacks diversification, and strong recent performance often mean-reverts", "The expense ratio will increase after strong performance", "Energy is not a real sector"], correct: 1, explanation: "Sector ETFs concentrate in one industry, removing the diversification benefit of broad-market funds. Strong recent performance often triggers reversion to the mean. Buying after a big run-up is classic performance chasing.", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 41, question: "An investor holds a 3x leveraged bull ETF for one year. The underlying index returns 10% for the year. The investor's return is:", options: ["Exactly 30%", "More than 30% due to compounding", "Less than 30% due to volatility decay and daily reset mechanics", "The same as the underlying index"], correct: 2, explanation: "Leveraged ETFs reset daily. Due to volatility drag (the mathematical effect of daily compounding), the long-term return of a 3x ETF almost always deviates from 3× the index return. In volatile markets, you can lose money even when the index is flat.", difficulty: "advanced", topic: "etfs", learnLink: "etfs" },
  { id: 42, question: "An inverse ETF is designed to return -1× its benchmark daily. If the S&P 500 drops 2% on Monday and rises 2% on Tuesday, what is the inverse ETF's approximate cumulative return?", options: ["Exactly 0%", "Slightly negative due to the compounding effect of daily resets", "Exactly +4%", "Slightly positive"], correct: 1, explanation: "Day 1: inverse ETF gains 2% (value 102). Day 2: S&P rises 2%, inverse loses 2% of 102 = 99.96. The S&P is at 99.96 too, but the inverse ETF's daily reset means it doesn't perfectly offset over multiple days — both end slightly negative.", difficulty: "advanced", topic: "etfs", learnLink: "etfs" },
  { id: 43, question: "An ETF has $50 billion in AUM, another has $200 million. All else being equal, which is likely true?", options: ["The smaller fund will generate higher returns", "The larger fund likely has tighter bid-ask spreads, lower tracking error, and more liquidity", "AUM has no impact on investor experience", "The smaller fund is always a better value"], correct: 1, explanation: "Larger AUM generally means more liquidity (easier to trade), tighter bid-ask spreads (lower trading costs), and better index tracking due to economies of scale. Very small ETFs also carry closure risk.", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 44, question: "Why are inverse and leveraged ETFs generally inappropriate for long-term buy-and-hold investors?", options: ["They have higher expense ratios than index funds", "They're only available to institutional investors", "Daily reset mechanics cause returns to diverge significantly from the expected multiple over longer periods due to volatility decay", "They are illegal to hold for more than 30 days"], correct: 2, explanation: "Leveraged/inverse ETFs rebalance daily. Over multiple days, the compounding of daily returns causes path dependency and volatility decay. Even if you correctly predict the direction, your return will likely differ substantially from the expected multiple.", difficulty: "advanced", topic: "etfs", learnLink: "etfs" },

  // ── BONDS ──────────────────────────────────────────
  { id: 5, question: "If you buy a 10-year Treasury bond at par ($1,000) with a 4% coupon, and interest rates rise to 6% the next day, which is TRUE?", options: ["Your bond's market value drops, but you still receive $40/year in interest and $1,000 at maturity if held to term", "Your bond's coupon rate automatically adjusts to 6%", "You lose money no matter what because rates went up", "Your bond is now worth more because it was issued at a lower rate"], correct: 0, explanation: "If rates rise, your bond's market price falls (because new bonds pay 6%). But if you hold to maturity, you still get your $40/year coupon and $1,000 back. The loss is only realized if you sell before maturity.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 7, question: "A bond portfolio has an average duration of 7 years. If interest rates rise by 1 percentage point, the portfolio's value will approximately:", options: ["Rise by 7%", "Fall by 7%", "Fall by 1%", "Remain unchanged because bonds pay fixed coupons"], correct: 1, explanation: "Duration approximates the percentage price change for a 1% change in interest rates. A 7-year duration means ≈7% price decline per 1% rate increase. This is why long-duration bonds are riskier in rising-rate environments.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },
  { id: 28, question: "The yield curve has inverted: 2-year Treasuries yield 5.2% while 10-year Treasuries yield 4.1%. What does this historically signal?", options: ["The economy is booming and stocks will rise", "An economic slowdown or recession typically follows within 12-24 months, though timing is uncertain", "Bond investors are irrational and the signal is meaningless", "Inflation will immediately drop to zero"], correct: 1, explanation: "Yield curve inversions have preceded every U.S. recession since 1955 with only one false signal. The mechanism: investors expect the Fed will cut rates due to slowing growth, driving long-term yields below short-term. Timing is the challenge — recessions have followed anywhere from 6 to 24 months later.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },
  { id: 45, question: "A bond has a face value of $1,000, a coupon rate of 5%, and trades at $1,100. What is its current yield?", options: ["5.0%", "4.55%", "5.5%", "10%"], correct: 1, explanation: "Current yield = annual coupon / market price = $50 / $1,100 = 4.55%. The current yield is lower than the coupon rate because the bond trades at a premium (above par). If it traded at a discount, the current yield would exceed the coupon rate.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 46, question: "In a falling interest rate environment, callable bonds become LESS attractive to investors because:", options: ["The coupon payments decrease automatically", "The issuer is likely to redeem the bond early, forcing reinvestment at lower prevailing rates", "Callable bonds have higher default risk", "The bond's maturity date extends"], correct: 1, explanation: "When rates fall, issuers call their bonds and reissue at lower rates — leaving investors with cash to reinvest at unfavorable rates. This 'reinvestment risk' is why callable bonds typically offer higher yields than non-callable ones.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },
  { id: 47, question: "A BB-rated corporate bond yields 7.5% while a AAA-rated corporate bond yields 4.2%. The 3.3% difference is called:", options: ["The risk-free rate", "The credit spread — compensation for higher default risk", "The coupon rate", "The inflation premium"], correct: 1, explanation: "The credit spread is the additional yield investors demand for taking on credit (default) risk. Wider spreads indicate greater perceived risk. Credit spreads typically widen during recessions as default risk increases.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 48, question: "Inflation unexpectedly surges from 2% to 6%. Which bond type is BEST protected?", options: ["A 30-year fixed-rate Treasury bond", "A 10-year corporate bond", "Treasury Inflation-Protected Securities (TIPS)", "A high-yield junk bond"], correct: 2, explanation: "TIPS adjust their principal value based on CPI changes. When inflation surges, TIPS principal increases, which increases coupon payments (calculated on the adjusted principal). Nominal bonds lose real value as inflation rises.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 49, question: "Bond A has a duration of 3 years and Bond B has a duration of 12 years. Interest rates are expected to rise. Which positioning is more defensive?", options: ["Hold Bond B because longer duration means more income", "Hold both equally for diversification", "Hold Bond A because shorter duration means less price sensitivity to rising rates", "Duration is irrelevant to interest rate risk"], correct: 2, explanation: "Shorter duration = less price sensitivity. If rates rise 1%, Bond A falls ~3% while Bond B falls ~12%. In rising rate environments, shortening duration is a defensive move. Conversely, extending duration benefits you when rates fall.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },
  { id: 50, question: "An investor in the 37% federal tax bracket is comparing a 4% municipal bond with a 6% corporate bond. Which provides more after-tax income?", options: ["The corporate bond by a significant margin", "The municipal bond — its tax-equivalent yield is approximately 6.35%", "They provide identical after-tax income", "It depends on the investor's state of residence only"], correct: 1, explanation: "Tax-equivalent yield = muni yield / (1 - tax rate) = 4% / (1 - 0.37) = 6.35%. Since 6.35% > 6%, the municipal bond actually provides more after-tax income. This is why munis are most valuable to high-bracket investors.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },

  // ── RETIREMENT ──────────────────────────────────────
  { id: 11, question: "A 30-year-old in the 22% tax bracket expects to be in the 32% bracket in retirement. Which account type is MOST advantageous for new contributions?", options: ["Traditional IRA (deduct at 22% now)", "Roth IRA (pay 22% now, withdraw tax-free when bracket is 32%)", "Taxable brokerage account", "It makes no difference"], correct: 1, explanation: "When you expect your future tax rate to be higher, Roth is optimal: pay 22% tax on contributions now and avoid the 32% rate on withdrawals later. If you expected a lower future rate, Traditional would win.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 25, question: "Under the 4% rule, someone spending $60,000/year needs what portfolio size to retire?", options: ["$600,000", "$1,200,000", "$1,500,000", "$2,400,000"], correct: 2, explanation: "$60,000 × 25 = $1,500,000. The 4% rule means you need 25× your annual expenses. However, this rule was developed based on historical U.S. data and assumes a 30-year retirement — longer retirements may require a lower withdrawal rate.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 51, question: "A 75-year-old with $800,000 in a Traditional IRA forgets to take their RMD. What is the IRS penalty?", options: ["A $100 flat fee", "No penalty — RMDs are optional", "Up to 25% of the amount that should have been withdrawn (reduced to 10% if corrected promptly)", "Complete account forfeiture"], correct: 2, explanation: "The SECURE 2.0 Act reduced the RMD penalty from 50% to 25% (or 10% if corrected within 2 years). RMDs force tax-deferred account holders to begin drawing down and paying taxes. Missing them is one of the costliest retirement mistakes.", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },
  { id: 52, question: "Which of the following can you do at age 59½ that you cannot do at age 58?", options: ["Contribute to a Roth IRA", "Withdraw from a Traditional IRA without the 10% early withdrawal penalty", "Begin receiving Social Security benefits", "Open a 401(k) account"], correct: 1, explanation: "At 59½, the 10% early withdrawal penalty on Traditional IRA distributions is eliminated (though ordinary income tax still applies). Notable exceptions: the Rule of 55 allows penalty-free 401(k) withdrawals if you separate from service at 55+.", difficulty: "beginner", topic: "retirement", learnLink: "retirement" },
  { id: 53, question: "A retiree with $500,000 in a Traditional IRA does a $50,000 Roth conversion during a year their income is unusually low. What is the PRIMARY strategic benefit?", options: ["They avoid all taxes on the conversion", "They pay income tax at their current low bracket, permanently removing the $50,000 from future RMD obligations and higher-bracket taxation", "They can immediately withdraw the converted amount penalty-free", "The conversion reverses automatically if the market drops"], correct: 1, explanation: "Strategic Roth conversions in low-income years lock in a low tax rate on the converted amount. The money then grows tax-free, is never subject to RMDs, and can be withdrawn tax-free. This is especially powerful in the 'gap years' between retirement and Social Security/RMD age.", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },
  { id: 54, question: "A 403(b) plan is MOST similar to which of the following?", options: ["A Roth IRA", "A health savings account", "A 401(k) plan", "A taxable brokerage account"], correct: 2, explanation: "A 403(b) is essentially the nonprofit/public sector equivalent of a 401(k). Both offer pre-tax or Roth contributions, employer matching, and similar contribution limits. The main difference: 403(b) plans sometimes have more limited investment options.", difficulty: "beginner", topic: "retirement", learnLink: "retirement" },
  { id: 55, question: "An employee contributes $23,000 to a Roth 401(k). Their employer matches 50% into the Traditional 401(k). Why doesn't the employer match go into the Roth?", options: ["Employer matches are always pre-tax money and must go into the Traditional (pre-tax) side of the plan by IRS rules", "The employer chose not to match the Roth portion", "Roth 401(k)s don't allow employer matches", "There's no difference between where the match goes"], correct: 0, explanation: "By IRS rules, employer matching contributions are always made pre-tax and go into the Traditional portion, even if your contributions go to the Roth. This means your Roth 401(k) will have two 'buckets' — Roth (your contributions) and Traditional (employer match).", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },
  { id: 56, question: "An HSA offers 'triple tax advantage.' Which of the following is NOT one of the three tax benefits?", options: ["Tax-deductible contributions", "Tax-free investment growth", "Tax-free withdrawals for qualified medical expenses", "Employer match is never taxed, even when withdrawn for non-medical purposes"], correct: 3, explanation: "The triple tax benefit is: (1) contributions are tax-deductible, (2) investments grow tax-free, (3) withdrawals for qualified medical expenses are tax-free. Employer matches still follow the same rules — non-medical withdrawals before 65 incur tax + penalty.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 57, question: "An employee is 40% vested in their employer's 401(k) match after 2 years. They've received $20,000 in matching contributions. If they leave today, how much of the match do they keep?", options: ["$20,000 — all employer contributions are always theirs", "Nothing — 40% vesting means they need to reach 100%", "$8,000 — they keep 40% of the matched amount", "$12,000 — they keep the unvested portion"], correct: 2, explanation: "At 40% vested, the employee keeps 40% × $20,000 = $8,000 of employer match. The remaining $12,000 is forfeited. Your own contributions are always 100% yours. This is why understanding your vesting schedule matters before switching jobs.", difficulty: "beginner", topic: "retirement", learnLink: "retirement" },
  { id: 58, question: "A high earner making $250,000/year cannot contribute directly to a Roth IRA. They use the backdoor Roth strategy. What potential tax complication must they be aware of?", options: ["The strategy is illegal for high earners", "There are no complications — it always works perfectly", "The pro-rata rule: if they have existing pre-tax IRA balances, a portion of the conversion will be taxable", "They must wait 5 years before contributing"], correct: 2, explanation: "The pro-rata rule considers ALL your Traditional IRA balances when calculating the taxable portion of a conversion. If you have $95,000 pre-tax in IRAs and convert a $5,000 non-deductible contribution, only 5% (~$250) is tax-free, not the full $5,000.", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },

  // ── TAXES ──────────────────────────────────────────
  { id: 8, question: "You sell Stock A for a $10,000 gain and Stock B for a $6,000 loss in the same year. What is your net taxable capital gain?", options: ["$10,000 — losses don't offset gains", "$4,000 — losses offset gains dollar for dollar", "$6,000 — only the larger amount counts", "$16,000 — both are taxable"], correct: 1, explanation: "Capital losses directly offset capital gains. $10,000 gain - $6,000 loss = $4,000 net taxable gain. If your losses exceed gains, you can deduct up to $3,000 of net losses against ordinary income, carrying the rest forward.", difficulty: "intermediate", topic: "taxes", learnLink: "taxes" },
  { id: 59, question: "You sell a stock at a $5,000 loss on December 15th and buy the same stock on January 8th. What happens?", options: ["The $5,000 loss is fully deductible this tax year", "The wash sale rule disallows the loss because you repurchased within 30 days; the loss is added to the new shares' cost basis", "The loss is halved due to the year-end boundary", "The purchase in January is automatically cancelled"], correct: 1, explanation: "The wash sale rule applies to purchases 30 days before OR after the sale. Since January 8th is within 30 days, the $5,000 loss is disallowed — but it's not gone forever. It's added to the cost basis of the new shares, deferring the tax benefit.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 60, question: "You bought stock for $10,000 and sell it for $15,000 after 11 months. In the 32% tax bracket, your capital gains tax is approximately:", options: ["$750 (15% long-term rate)", "$1,600 (32% ordinary income rate)", "$0 — gains under $15,000 are exempt", "$2,500 (50% penalty rate for short-term)"], correct: 1, explanation: "Held for 11 months = short-term capital gain, taxed as ordinary income. $5,000 gain × 32% = $1,600. If you'd waited one more month (12+ months), it would qualify for the 15% long-term rate, saving you $850. Holding period matters enormously.", difficulty: "intermediate", topic: "taxes", learnLink: "taxes" },
  { id: 61, question: "A recent retiree has $0 in other income this year. They have $40,000 in unrealized long-term capital gains. Why might they deliberately sell and 'harvest' these GAINS?", options: ["They're legally required to realize gains each year", "At $0 income, long-term capital gains up to ~$47,000 are taxed at 0% — they can reset their cost basis for free", "It reduces their portfolio value for Medicaid eligibility", "Realized gains are always tax-free in retirement"], correct: 1, explanation: "Tax-gain harvesting exploits the 0% long-term capital gains bracket (up to ~$47,000 for single filers). By selling and immediately rebuying, you reset your cost basis higher — eliminating future tax liability on those gains. It's only possible when your taxable income is very low.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 62, question: "You hold REITs, international stock funds, and a total U.S. stock index fund. For optimal asset location, where should you place each?", options: ["All in a Roth IRA for simplicity", "REITs in tax-advantaged accounts, international funds in taxable (for foreign tax credit), U.S. index in either", "It doesn't matter — asset location has minimal impact", "All in a taxable account for maximum flexibility"], correct: 1, explanation: "REITs generate ordinary income (no qualified dividend treatment) — best in tax-sheltered accounts. International funds in taxable accounts let you claim the foreign tax credit. Tax-efficient U.S. index funds work well anywhere. Proper location can add 0.5-1% annually.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 63, question: "You receive $1,000 in qualified dividends and $500 in non-qualified dividends. In the 24% ordinary income bracket with a 15% long-term rate, what total tax do you owe on these dividends?", options: ["$360 total", "$225 total", "$270 total", "$150 total"], correct: 2, explanation: "Qualified dividends: $1,000 × 15% = $150. Non-qualified dividends: $500 × 24% = $120. Total: $270. The distinction matters — qualified dividends (from most U.S. stocks held 60+ days) get the preferential rate; non-qualified are taxed as ordinary income.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 64, question: "Your parent bought stock at $20/share 40 years ago. It's worth $200/share when they pass away and you inherit it. What is your cost basis?", options: ["$20 — original purchase price carries over", "The average of $20 and $200 ($110)", "$200 — the step-up in basis resets to fair market value at death", "$0 — inherited assets have no cost basis"], correct: 2, explanation: "The step-up in basis at death resets inherited assets to their fair market value, eliminating all unrealized capital gains. This is one of the most significant (and controversial) tax benefits in the U.S. code. The $180/share of gains is permanently untaxed.", difficulty: "intermediate", topic: "taxes", learnLink: "taxes" },

  // ── BEHAVIORAL FINANCE ──────────────────────────────
  { id: 14, question: "Research shows the pain of losing $1,000 is psychologically equivalent to the pleasure of gaining approximately:", options: ["$1,000 — losses and gains feel equal", "Between $1,500 and $2,500 — losses feel roughly 1.5-2.5× more painful than equivalent gains feel good", "Exactly $10,000 — losses feel 10× worse", "$500 — gains actually feel better than losses feel bad"], correct: 1, explanation: "Kahneman and Tversky's prospect theory found losses are felt approximately 2-2.5× as intensely as equivalent gains. This 'loss aversion' causes investors to hold losers too long, sell winners too early, and avoid beneficial volatility.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 65, question: "An investor only reads bullish analysis about a stock they own and dismisses all bearish reports. They are exhibiting:", options: ["Due diligence", "Confirmation bias — selectively seeking information that validates existing beliefs", "Prudent risk management", "Fundamental analysis"], correct: 1, explanation: "Confirmation bias leads investors to create an echo chamber of validating information. The antidote: actively seek out the best bear case for every investment you hold. If you can't articulate why you might be wrong, you haven't done enough research.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 66, question: "You've held a stock for 3 years at a total loss of $15,000. The company's fundamentals have deteriorated. A friend says 'you've already lost so much, might as well hold and hope.' This reasoning is:", options: ["Sound advice — you should always hold until you break even", "The sunk cost fallacy — past losses are irrelevant to the decision; only the stock's future prospects matter", "A valid tax strategy", "Correct because selling would realize the loss"], correct: 1, explanation: "The sunk cost fallacy makes us factor in past, irrecoverable costs when making forward-looking decisions. The $15,000 loss exists whether you hold or sell. The only question that matters: 'If I had this cash today, would I buy this stock?' If not, sell.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 67, question: "A stock dropped from $150 to $80. An investor thinks 'it's cheap because it used to be $150.' This cognitive error is:", options: ["Value investing", "Sound technical analysis", "Anchoring bias — fixating on an irrelevant reference price rather than assessing current intrinsic value", "Mean reversion theory"], correct: 2, explanation: "The previous price of $150 is an anchor with no bearing on current fair value. The stock at $80 could still be overvalued if fundamentals deteriorated. Anchoring causes investors to buy 'dips' in fundamentally broken companies.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 68, question: "An investor's portfolio has two stocks: one up 40%, one down 30%. They need cash and sell the winner. This decision pattern is called:", options: ["Tax-loss harvesting", "Prudent portfolio management", "Rebalancing", "The disposition effect — selling winners to feel good while holding losers to avoid the pain of realizing a loss"], correct: 3, explanation: "The disposition effect causes investors to sell winners prematurely (locking in the pleasure of a gain) and hold losers (avoiding the pain of admitting a mistake). Tax-wise, it's backwards — you should harvest losses for the tax benefit.", difficulty: "advanced", topic: "behavioral", learnLink: "behavioral" },
  { id: 69, question: "An investor keeps their inheritance in a separate 'sacred' account and won't touch it, while carrying $12,000 in credit card debt at 24% APR. This is an example of:", options: ["Sound estate planning", "Mental accounting — treating money differently based on its source rather than optimizing total financial position", "Responsible investing", "Proper asset allocation"], correct: 1, explanation: "Mental accounting causes people to create artificial buckets for money. Rationally, using inheritance to pay off 24% debt is an instant guaranteed 24% return. But the emotional label of 'inheritance money' prevents the optimal financial decision.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 70, question: "Bitcoin rose 300% last year. Your coworker quit to day-trade crypto. You feel compelled to invest your emergency fund. Which TWO biases are most at play?", options: ["Survivorship bias and anchoring", "FOMO (fear of missing out) and social proof/herd mentality", "Loss aversion and endowment effect", "Recency bias and overconfidence"], correct: 1, explanation: "FOMO creates urgency ('I'll miss the opportunity'), while social proof ('my coworker is doing it') validates the impulse. Together they're powerful — and usually peak right before the worst time to invest. Emergency funds should never be risked on speculative assets.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 71, question: "After a 3-year bull market, investors allocate more to stocks than their plan dictates, saying 'the market always goes up.' After a 6-month decline, they sell everything. Which bias drives BOTH actions?", options: ["Confirmation bias", "Anchoring bias", "Recency bias — overweighting recent experience and projecting it indefinitely into the future", "The Dunning-Kruger effect"], correct: 2, explanation: "Recency bias causes investors to extrapolate the recent past: after gains, they expect more gains (overallocating); after losses, they expect more losses (panic selling). A written investment plan followed regardless of recent performance is the antidote.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 72, question: "A self-taught investor has beaten the market for 2 years and doubles their portfolio concentration into 3 stocks. What is the likely outcome and which bias is responsible?", options: ["They'll continue outperforming because skill always persists", "Overconfidence bias — a short track record doesn't validate skill; increased concentration amplifies risk of catastrophic loss", "They've demonstrated enough skill to justify concentration", "This is a sound value investing approach"], correct: 1, explanation: "2 years of outperformance is statistically insignificant — it takes 20+ years to distinguish skill from luck. Overconfidence after a hot streak leads to excessive risk-taking. Most professional traders who concentrate after a winning streak eventually suffer devastating losses.", difficulty: "advanced", topic: "behavioral", learnLink: "behavioral" },

  // ── GENERAL INVESTING ──────────────────────────────
  { id: 3, question: "$10,000 invested at 8% annual return for 30 years with no additional contributions becomes approximately:", options: ["$34,000", "$ 80,000", "$100,627", "$180,000"], correct: 2, explanation: "$10,000 × (1.08)^30 = $100,627. This is pure compound interest with zero additional contributions. The original $10,000 generated over $90,000 in returns on returns. Starting 10 years later with the same amount would yield only $46,610.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 19, question: "Using the Rule of 72, how long does it take to double your money at a 6% annual return? And at 12%?", options: ["12 years and 6 years", "6 years and 12 years", "18 years and 9 years", "10 years and 5 years"], correct: 0, explanation: "Rule of 72: 72 ÷ 6 = 12 years. 72 ÷ 12 = 6 years. This quick mental math tool reveals that the difference between 6% and 12% returns isn't just 'twice as fast' — it's the difference between doubling 2.5 times vs. 5 times in 30 years.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 23, question: "Rank these assets from MOST to LEAST liquid: (1) Real estate, (2) S&P 500 ETF, (3) Small-cap penny stock, (4) Private equity fund", options: ["2, 3, 1, 4", "2, 1, 3, 4", "3, 2, 1, 4", "1, 2, 3, 4"], correct: 0, explanation: "S&P 500 ETFs trade billions of shares daily (most liquid). Penny stocks trade but with wide spreads and low volume. Real estate takes weeks-months to sell. Private equity funds often lock up capital for 7-10 years (least liquid).", difficulty: "intermediate", topic: "general", learnLink: "stocks" },
  { id: 27, question: "An investor adds $100,000 to their portfolio the day before a 20% market drop. Their time-weighted return is -20%, but their dollar-weighted return is much worse. Why?", options: ["Time-weighted return is always higher", "Dollar-weighted return accounts for the TIMING of cash flows — the large addition right before the drop amplifies the personal loss", "The calculations are wrong", "Dollar-weighted return ignores contributions"], correct: 1, explanation: "Dollar-weighted (IRR) reflects your personal experience including cash flow timing. Adding a large sum right before a drop means most of your capital experienced the full decline. Time-weighted return measures the strategy's return regardless of when you added money.", difficulty: "advanced", topic: "general", learnLink: "index-funds" },
  { id: 73, question: "Portfolio A returned 12% with a standard deviation of 20%. Portfolio B returned 9% with a standard deviation of 8%. The risk-free rate is 3%. Which has the better Sharpe ratio?", options: ["Portfolio A (Sharpe = 0.45)", "Portfolio B (Sharpe = 0.75)", "They are equal", "Cannot be determined without the beta"], correct: 1, explanation: "Sharpe ratio = (Return - Risk-free rate) / Std Dev. A: (12-3)/20 = 0.45. B: (9-3)/8 = 0.75. Portfolio B delivers better RISK-ADJUSTED returns despite lower absolute returns. A higher Sharpe means more return per unit of risk.", difficulty: "advanced", topic: "general", learnLink: "diversification" },
  { id: 74, question: "Your portfolio gained 10% this year. Inflation was 4%. Your real return is approximately:", options: ["14%", "10%", "6%", "4%"], correct: 2, explanation: "Real return ≈ nominal return - inflation = 10% - 4% = 6%. (The precise formula is (1.10/1.04)-1 = 5.77%). Always evaluate investment performance in real terms — a 10% return with 9% inflation is barely better than a savings account.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 75, question: "You rebalance your 70/30 stock/bond portfolio annually. After a year, stocks have surged and your allocation is 82/18. Rebalancing requires you to:", options: ["Buy more stocks because they're performing well", "Sell stocks and buy bonds to return to 70/30, which feels counterintuitive but systematically buys low and sells high", "Do nothing until the allocation drifts further", "Sell everything and start over"], correct: 1, explanation: "Rebalancing forces you to sell what's risen (high) and buy what's lagged (low) — the opposite of emotional investing. It controls risk and has been shown to improve risk-adjusted returns over time, even though it feels wrong to sell winners.", difficulty: "intermediate", topic: "general", learnLink: "diversification" },
  { id: 76, question: "The classic 3-fund portfolio (VTI/VXUS/BND) provides exposure to approximately how many individual securities?", options: ["About 500", "About 3,000", "Over 15,000 stocks and thousands of bonds", "Exactly 3"], correct: 2, explanation: "VTI holds ~4,000 U.S. stocks, VXUS holds ~8,000 international stocks, and BND holds thousands of U.S. bonds. Three simple funds give you exposure to virtually the entire global investable market. Maximum diversification, minimum complexity.", difficulty: "beginner", topic: "general", learnLink: "diversification" },
  { id: 77, question: "An investor buys $50,000 of stock on margin with $25,000 of their own money (50% margin). The stock drops 30%. What is the investor's actual loss percentage on their $25,000?", options: ["30%", "50%", "60%", "15%"], correct: 2, explanation: "The $50,000 position drops 30% = $15,000 loss. But the investor only put up $25,000. $15,000 / $25,000 = 60% loss on their actual capital. Margin amplifies losses (and gains) proportionally to leverage. A 50% stock decline would wipe out the investor entirely.", difficulty: "advanced", topic: "general", learnLink: "stocks" },
  { id: 78, question: "Your portfolio drops 15% during a recession. You panic but then learn: is this systematic risk, unsystematic risk, or both?", options: ["Unsystematic — you should have diversified better", "Systematic — recessions affect the entire market and cannot be diversified away", "Both equally", "Neither — recessions don't affect portfolios"], correct: 1, explanation: "A recession causing broad market declines is systematic (market) risk — it affects virtually all stocks. Diversification eliminates unsystematic risk (company-specific), but not systematic risk. The only way to reduce systematic risk is to allocate less to stocks (more to bonds/cash).", difficulty: "intermediate", topic: "general", learnLink: "diversification" },
  { id: 79, question: "Historically, what is the average first-day return of IPOs, and what does the average 3-year return look like compared to the market?", options: ["IPOs underperform on day one but outperform over 3 years", "IPOs tend to 'pop' 10-15% on day one but underperform the broader market over 3-5 years on average", "IPOs consistently outperform at all time horizons", "IPOs have no predictable pattern"], correct: 1, explanation: "The average IPO pops ~15% on day one (mostly captured by institutional investors, not retail). But academic research consistently shows IPOs underperform the market over 3-5 years. The excitement and limited float create initial froth that typically fades.", difficulty: "advanced", topic: "general", learnLink: "stocks" },
  { id: 80, question: "A company announces a $10 billion share buyback. What is the likely effect on EPS, even if net income stays flat?", options: ["EPS decreases because the company spent cash", "EPS increases because the same earnings are divided among fewer shares", "No effect — buybacks don't impact financial metrics", "EPS only changes if revenue grows"], correct: 1, explanation: "Buybacks reduce shares outstanding. Same net income ÷ fewer shares = higher EPS. Critics argue this can make a stagnant company look like it's growing. Investors should check whether EPS growth is driven by genuine profit growth or financial engineering.", difficulty: "intermediate", topic: "general", learnLink: "stocks" },
  { id: 81, question: "Which statement about Roth IRA vs. taxable brokerage accounts is FALSE?", options: ["Roth IRA contributions can be withdrawn anytime without tax or penalty", "Roth IRA has annual contribution limits; brokerage accounts do not", "Taxable accounts allow tax-loss harvesting; Roth IRAs do not (since there's no tax on gains)", "Brokerage account gains are tax-free if held for more than 5 years"], correct: 3, explanation: "Brokerage gains are NEVER tax-free just based on holding period. Long-term gains (held >1 year) get preferential rates (0/15/20%), but are still taxed. The other three statements are all true.", difficulty: "intermediate", topic: "general", learnLink: "retirement" },

  // ── INDEX FUNDS ──────────────────────────────────────
  { id: 15, question: "Over 15-year periods, what percentage of actively managed U.S. large-cap funds underperform the S&P 500?", options: ["About 50% — it's basically a coin flip", "About 70%", "Over 90%", "Less than 30% — most managers add value"], correct: 2, explanation: "SPIVA data consistently shows 90%+ of active large-cap managers underperform their benchmark over 15 years. After fees, the odds of picking a winning active fund in advance are extremely low. This is the strongest empirical argument for index investing.", difficulty: "intermediate", topic: "index-funds", learnLink: "index-funds" },

  // ── DIVERSIFICATION ──────────────────────────────────
  { id: 4, question: "An investor owns 30 different tech stocks and considers themselves 'well diversified.' What is the flaw in this reasoning?", options: ["30 stocks is too few for diversification", "Sector concentration means all holdings are exposed to the same systematic risks — diversification requires exposure across different sectors, asset classes, and geographies", "Tech stocks don't count for diversification", "There is no flaw — 30 stocks is always sufficient"], correct: 1, explanation: "True diversification requires exposure to assets that don't move in lockstep. 30 tech stocks will all drop together during a tech selloff. Adding bonds, international stocks, REITs, and other sectors reduces correlation and portfolio volatility.", difficulty: "intermediate", topic: "diversification", learnLink: "diversification" },
  { id: 17, question: "Studies show asset allocation determines approximately what percentage of a portfolio's return variability over time?", options: ["About 25%", "About 50%", "About 90%", "About 100%"], correct: 2, explanation: "The famous Brinson study found that asset allocation (stocks vs. bonds vs. other asset classes) explains about 90% of the variability of portfolio returns over time. Individual security selection and market timing account for the remaining ~10%.", difficulty: "intermediate", topic: "diversification", learnLink: "diversification" },
  { id: 29, question: "Two assets have a correlation of -0.3. When combined in a portfolio, what happens to the overall risk?", options: ["Risk increases because negative correlation means negative returns", "Risk is unchanged — correlation doesn't affect portfolio risk", "Risk decreases more than it would with uncorrelated (0) or positively correlated assets", "Risk is completely eliminated"], correct: 2, explanation: "Negative correlation means the assets tend to move in opposite directions. When combined, one asset's losses are partially offset by the other's gains, reducing portfolio volatility more effectively than combining assets with zero or positive correlation.", difficulty: "advanced", topic: "diversification", learnLink: "diversification" },

  // ── DCA ──────────────────────────────────────────
  { id: 10, question: "You invest $500/month for 12 months. The stock price is $50 for 6 months then $25 for 6 months. Your average cost per share is:", options: ["$37.50 (simple average of $50 and $25)", "Less than $37.50, because you bought more shares at the lower price", "$50, because you started at that price", "$25, because that was the most recent price"], correct: 1, explanation: "At $50: 6 months × $500/$50 = 60 shares. At $25: 6 months × $500/$25 = 120 shares. Total: 180 shares for $6,000 = $33.33/share. DCA's math naturally creates a below-average cost because fixed dollar amounts buy more shares when prices are low.", difficulty: "intermediate", topic: "dca", learnLink: "dca" },

  // ── DIVIDENDS ──────────────────────────────────────
  { id: 16, question: "A stock pays a $3.00 annual dividend and trades at $75. If the price drops to $60 with no dividend change, the yield:", options: ["Drops to 4%", "Stays at 4%", "Rises to 5% — yield moves inversely to price when dividends are constant", "Cannot be calculated without knowing the payout ratio"], correct: 2, explanation: "Yield = dividend / price. At $75: $3/$75 = 4%. At $60: $3/$60 = 5%. A falling stock price mechanically increases the dividend yield if the dividend amount stays constant. This is why unusually high yields can be warning signs (yield traps).", difficulty: "intermediate", topic: "dividends", learnLink: "dividends" },

  // ── REITs ──────────────────────────────────────────
  { id: 9, question: "REITs must distribute at least 90% of taxable income as dividends. What is the PRIMARY tax consequence for investors?", options: ["REIT dividends are always tax-free", "REIT dividends are taxed at the lower qualified dividend rate", "Most REIT dividends are taxed as ordinary income (not qualified dividends), making tax-advantaged accounts optimal", "REITs have no tax consequences"], correct: 2, explanation: "Unlike most stock dividends that qualify for the lower capital gains rate, REIT dividends are generally taxed as ordinary income (up to 37%). This is why financial planners recommend holding REITs inside IRAs or 401(k)s for tax efficiency.", difficulty: "intermediate", topic: "reits", learnLink: "reits" },
  { id: 82, question: "When evaluating a REIT, why is FFO (Funds From Operations) preferred over traditional net income?", options: ["FFO is always higher than net income", "Net income includes depreciation, which overstates the decline in value of real estate assets that typically appreciate", "FFO ignores all expenses, giving a cleaner picture", "There is no meaningful difference between the two"], correct: 1, explanation: "Real estate typically appreciates over time, but accounting rules require depreciation to be deducted from net income. FFO adds back depreciation to give a more accurate picture of a REIT's actual cash-generating ability.", difficulty: "advanced", topic: "reits", learnLink: "reits" },
  { id: 83, question: "During a period of rapidly rising interest rates, which REIT type is MOST negatively affected and why?", options: ["Equity REITs because property values always crash", "Mortgage REITs (mREITs), because rising rates decrease the value of their mortgage-backed securities and compress net interest margins", "Neither type is affected by interest rates", "Both are affected equally"], correct: 1, explanation: "Mortgage REITs hold fixed-rate mortgage assets financed with shorter-term borrowings. Rising rates decrease asset values while increasing borrowing costs, compressing margins from both sides. Equity REITs are affected too, but can often raise rents to offset.", difficulty: "advanced", topic: "reits", learnLink: "reits" },
  { id: 84, question: "A property generates $120,000 in net operating income and is valued at $1,500,000. A similar property nearby has a cap rate of 6%. Is this property fairly priced?", options: ["Yes — its cap rate matches the area", "No — its cap rate is 8%, which suggests it may be underpriced relative to the comparable property at 6%", "No — it's overpriced because the NOI is too low", "Cap rates cannot be compared between properties"], correct: 1, explanation: "Cap rate = NOI / Value = $120,000 / $1,500,000 = 8%. A higher cap rate than comparable properties suggests higher return (and potentially higher risk) or undervaluation. The investor is getting more income per dollar invested than the comparable.", difficulty: "advanced", topic: "reits", learnLink: "reits" },
  { id: 85, question: "Which mechanism allows REITs to provide better inflation protection than traditional bonds?", options: ["REIT dividends are indexed to CPI like TIPS", "REITs hold Treasury bonds as a hedge", "Lease agreements often include rent escalation clauses, and property replacement costs rise with inflation", "REITs are unaffected by inflation"], correct: 2, explanation: "Many commercial leases include annual rent escalation clauses (often CPI-linked). Additionally, the cost to build new competing properties rises with inflation, supporting the value of existing properties. Bonds, by contrast, pay fixed coupons that lose purchasing power.", difficulty: "intermediate", topic: "reits", learnLink: "reits" },

  // ── OPTIONS ──────────────────────────────────────────
  { id: 20, question: "An investor sells a covered call with a $110 strike on 100 shares of stock they own at $100, collecting a $3 premium. What is the maximum profit on this combined position?", options: ["Unlimited", "$300 (just the premium)", "$1,300 ($10 appreciation + $3 premium × 100 shares)", "$1,000"], correct: 2, explanation: "Maximum profit = (strike - stock price + premium) × shares = ($110 - $100 + $3) × 100 = $1,300. If the stock goes above $110, the shares are called away. The covered call caps upside in exchange for the premium income.", difficulty: "advanced", topic: "options", learnLink: "options" },
  { id: 86, question: "An option loses $0.05 of value per day due to theta decay. With 60 days until expiration, theta decay will:", options: ["Remain constant at $0.05/day until expiration", "Slow down as expiration approaches", "Accelerate significantly — theta decay is non-linear and increases dramatically in the final 30 days", "Only affect the option on the expiration date"], correct: 2, explanation: "Theta decay follows a non-linear curve resembling a hockey stick. Options lose time value slowly early on, but decay accelerates exponentially in the final 30-45 days. This is why short-term options are riskier for buyers and more profitable for sellers.", difficulty: "advanced", topic: "options", learnLink: "options" },
  { id: 87, question: "A call option has a strike price of $50. The stock is trading at $53. The option premium is $5. What is the option's intrinsic value and time value?", options: ["Intrinsic: $5, Time: $0", "Intrinsic: $3, Time: $2", "Intrinsic: $0, Time: $5", "Intrinsic: $53, Time: $50"], correct: 1, explanation: "Intrinsic value = stock price - strike = $53 - $50 = $3 (the 'real' value). Time value = premium - intrinsic = $5 - $3 = $2 (what you're paying for the chance the stock goes higher before expiration). At expiration, time value is zero.", difficulty: "intermediate", topic: "options", learnLink: "options" },
  { id: 88, question: "An investor owns 500 shares of XYZ at $100 and buys 5 protective put contracts (100 shares each) with a $90 strike for $3 per share. What is their maximum loss?", options: ["Unlimited", "$5,000 (the drop from $100 to $90)", "$6,500 — the $10/share decline to the strike plus the $3/share premium paid", "Zero — puts eliminate all risk"], correct: 2, explanation: "Max loss = (stock price - strike + put premium) × shares = ($100 - $90 + $3) × 500 = $6,500. The put guarantees you can sell at $90, but you paid $3/share for that insurance. Below $90, losses stop. It's portfolio insurance with a known cost.", difficulty: "advanced", topic: "options", learnLink: "options" },
  { id: 89, question: "Implied volatility on a stock spikes from 20% to 60% ahead of an earnings announcement. What happens to option prices and what strategy might exploit this?", options: ["Option prices drop — high IV means less uncertainty", "Option prices surge because higher IV increases the probability of large moves; selling options (like iron condors) can profit if IV contracts after earnings", "Only call prices are affected, not puts", "IV has no effect on option pricing"], correct: 1, explanation: "Higher implied volatility directly increases both call and put prices (through the Vega component). If you believe IV is temporarily inflated, selling options captures the premium. After earnings, IV typically 'crushes' back to normal, benefiting option sellers.", difficulty: "advanced", topic: "options", learnLink: "options" },

  // ── HEDGE FUNDS ──────────────────────────────────────
  { id: 18, question: "The typical hedge fund charges '2 and 20.' On a $1 million investment that gains 15% in a year, what are the total fees?", options: ["$20,000", "About $50,000 ($20K management + $30K performance fee on gains)", "About $200,000", "$2,000"], correct: 1, explanation: "2% management fee on $1M = $20,000. 20% performance fee on $150,000 gain = $30,000. Total: $50,000, or 5% of the portfolio. Compare this to a 0.03% index fund charging just $300. The hedge fund must dramatically outperform to justify 167× higher fees.", difficulty: "advanced", topic: "hedge-funds", learnLink: "hedge-funds" },

  // ── ADDITIONAL GENERAL ──────────────────────────────
  { id: 90, question: "Your financial advisor recommends a mutual fund that pays them a 5% front-end load. They are likely a:", options: ["Fiduciary — required to act in your best interest", "Commission-based advisor with a potential conflict of interest", "Fee-only advisor", "Robo-advisor"], correct: 1, explanation: "Fiduciaries are legally required to act in your best interest and wouldn't typically recommend load funds. A commission-based advisor earns income from product sales, creating conflicts. Always ask: 'Are you a fiduciary? How are you compensated?'", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 91, question: "If markets are truly efficient (strong form EMH), which investment strategy is optimal?", options: ["Actively managed funds run by expert stock pickers", "Technical analysis and chart patterns", "Low-cost, broad-market index funds — since no one can consistently gain an informational edge", "Insider-informed trading"], correct: 2, explanation: "Under strong EMH, all information (public and private) is already reflected in prices. No analysis can consistently produce above-market returns after costs. The logical conclusion: own the entire market cheaply through index funds and accept the market return.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 92, question: "An investor enables DRIP on a stock paying $1,000/year in dividends. After 20 years at 8% growth, the reinvested dividends alone are worth approximately:", options: ["$20,000 (just the dividends accumulated)", "About $46,000 due to compounding of reinvested dividends", "About $100,000", "The exact same as receiving cash dividends"], correct: 1, explanation: "DRIP turns dividend income into additional shares that themselves generate dividends. $1,000/year reinvested at 8% for 20 years ≈ $46,000. Without reinvestment, you'd just have $20,000 in cash. The ~$26,000 difference is compound growth on reinvested dividends.", difficulty: "intermediate", topic: "dividends", learnLink: "dividends" },
  { id: 93, question: "A target-date 2055 fund today likely holds approximately:", options: ["100% bonds for safety", "90% stocks / 10% bonds — aggressive because retirement is 30+ years away", "50/50 stocks and bonds", "100% cash equivalents"], correct: 1, explanation: "With 30+ years until the target date, the fund maintains an aggressive allocation (~90% stocks). As 2055 approaches, it automatically shifts toward bonds (the 'glide path'). By 2055, it might be 40% stocks / 60% bonds. It's a single-fund retirement solution.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 94, question: "A fee-only financial advisor charges 1% of AUM annually. On a $1 million portfolio, how much will you pay over 25 years (assuming 8% growth and 1% fee deducted)?", options: ["$250,000 total", "About $170,000 total", "About $430,000 in cumulative fees", "Only $10,000/year = $250,000 total"], correct: 2, explanation: "The 1% fee is charged on the growing portfolio, not just the original amount. As the portfolio grows, so does the dollar amount of the fee. Over 25 years, cumulative fees approach $430,000. You need to assess whether the advice provided is worth roughly half a million dollars.", difficulty: "advanced", topic: "general", learnLink: "index-funds" },
  { id: 95, question: "DCA investors who continued investing $500/month through the 2008-2009 crash (S&P 500 fell ~55%) saw what result by 2013?", options: ["They lost most of their investment and never recovered", "They were still underwater 5 years later", "They significantly outperformed investors who stopped contributing, because they bought many shares at deeply discounted prices", "Their results were identical to those who stopped investing"], correct: 2, explanation: "Investors who maintained DCA through the crash accumulated shares at 50-60% discounts. When markets recovered by 2013, those discounted shares amplified gains. Investors who stopped contributing missed the cheapest buying opportunity in a generation.", difficulty: "intermediate", topic: "dca", learnLink: "dca" },
  { id: 96, question: "A study found that missing just the 10 best trading days over a 20-year period cuts total returns by roughly:", options: ["5%", "20%", "50% or more", "It has no significant impact"], correct: 2, explanation: "JP Morgan research showed that $10,000 invested in the S&P 500 from 2003-2022 grew to $64,844. Missing the 10 best days: $29,708 (54% less). The best days often occur near the worst days — you can't capture them by timing the market. Stay invested.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 97, question: "A company has increased its dividend for 30 consecutive years, qualifying as a Dividend Aristocrat. It just announced flat earnings and rising debt. Should you buy based on the streak?", options: ["Yes — 30 years of increases guarantees future increases", "The streak is impressive but doesn't override deteriorating fundamentals; the dividend may be at risk if earnings don't support it", "Aristocrats never cut their dividends", "The debt increase is irrelevant to dividend sustainability"], correct: 1, explanation: "Dividend streaks are backward-looking. Companies like GE and AT&T had decades-long streaks before cutting dividends when fundamentals deteriorated. Always evaluate payout ratio, free cash flow coverage, and debt trends alongside the historical record.", difficulty: "advanced", topic: "dividends", learnLink: "dividends" },
  { id: 98, question: "During a bear market, the S&P 500 drops 25% and then rallies 15% over 3 weeks. What is this rally called and what typically happens next?", options: ["The start of a new bull market — the bottom is in", "A bear market rally — a temporary bounce within a broader downtrend that often fools investors into thinking the worst is over", "A market correction", "A flash crash recovery"], correct: 1, explanation: "Bear market rallies are deceptive bounces within ongoing downtrends. The 2008 bear market had multiple 10-20% rallies before the ultimate bottom in March 2009. These rallies create false hope and trap investors who buy too early.", difficulty: "intermediate", topic: "general", learnLink: "stocks" },
  { id: 99, question: "You set a stop-loss at $90 on a stock trading at $100. Overnight, bad earnings cause the stock to open at $75. Your shares are sold at:", options: ["$90 — your stop-loss guarantees that price", "$75 or the best available price — stop-loss orders convert to market orders and don't guarantee your stop price", "$100 — the previous close price", "They won't sell because the stock gapped past your stop"], correct: 1, explanation: "Stop-loss orders become market orders once the stop price is triggered. If the stock gaps past your stop (opens below $90), you'll sell at the market opening price (~$75). This 'gap risk' is why stop-losses don't provide the protection many investors assume.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 100, question: "Research shows lump-sum investing beats DCA approximately 67% of the time. Why might a rational investor still choose DCA?", options: ["DCA always produces higher returns", "DCA minimizes regret risk — the psychological cost of investing a lump sum right before a drop can cause permanent behavioral damage (panic selling)", "Lump-sum investing is too risky for anyone", "There's no rational reason to choose DCA"], correct: 1, explanation: "The mathematical advantage of lump-sum is small (~2.3% over 12 months). But the regret of investing $200K the day before a 20% crash can cause panic selling — destroying far more than 2.3%. DCA's behavioral advantage often outweighs the mathematical disadvantage.", difficulty: "advanced", topic: "dca", learnLink: "dca" },
  { id: 101, question: "A retiree withdraws 4% ($40,000) from their $1,000,000 portfolio. In year one, the market drops 30%. Their portfolio is now approximately:", options: ["$700,000", "$660,000 — the withdrawal compounds the market loss, demonstrating sequence-of-returns risk", "$960,000", "$580,000"], correct: 1, explanation: "($1,000,000 - $40,000 withdrawal) × (1 - 0.30) = $672,000 (or ~$660K allowing for withdrawal timing). The combination of withdrawals + early losses is devastating. This 'sequence risk' is why retirees need cash buffers and lower equity exposure.", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },
  { id: 102, question: "An income investor chooses between: (A) a stock yielding 2% growing dividends 10%/year, or (B) a stock yielding 6% with no growth. After 10 years, which likely provides more annual income on the original investment?", options: ["Stock B — 6% yield is always better than 2%", "Stock A — the 2% yield growing at 10%/year reaches ~5.2% yield-on-cost by year 10, with price appreciation as a bonus", "They'll be approximately equal", "Cannot be determined"], correct: 1, explanation: "Stock A's dividend doubles roughly every 7 years (Rule of 72). By year 10: 2% × (1.10)^10 ≈ 5.2% yield on original cost, approaching Stock B's 6% — plus Stock A likely appreciated significantly in price. High-growth dividends often overtake high-current-yield stocks.", difficulty: "advanced", topic: "dividends", learnLink: "dividends" },
  { id: 103, question: "A married couple earns $100,000 and contributes $10,000 to a 529 plan. In their state, 529 contributions are deductible. If their state tax rate is 5%, what is the immediate tax benefit?", options: ["$0 — 529 contributions are never deductible", "$500 state tax savings", "$10,000 deduction from federal taxes", "$5,000 savings"], correct: 1, explanation: "529 contributions are deductible on state taxes in most (but not all) states. $10,000 × 5% state rate = $500 immediate savings. There's no federal deduction, but growth is tax-free and withdrawals for qualified education expenses are tax-free.", difficulty: "intermediate", topic: "general", learnLink: "taxes" },
  { id: 104, question: "What is the most COMPELLING argument for index investing, based on data?", options: ["Index funds have zero risk", "Index funds guarantee above-average returns", "After fees and over 15+ year periods, index funds outperform 90%+ of professional money managers — and you don't need to pick the right manager in advance", "Index funds never lose money in any calendar year"], correct: 2, explanation: "The argument isn't about index funds being 'safe' or 'guaranteed' — they can lose significantly in any given year. The argument is probabilistic: over long periods, the vast majority of professionals fail to beat the index after fees, so why try?", difficulty: "intermediate", topic: "index-funds", learnLink: "index-funds" },
  { id: 105, question: "A 'correction' (10-20% decline) occurs in the stock market roughly how often?", options: ["Once every 10 years", "Once every 3-5 years", "About once per year on average", "Only during recessions"], correct: 2, explanation: "Market corrections of 10%+ occur roughly once a year on average. They're a normal part of market behavior, not an emergency. Investors who understand this frequency are far less likely to panic sell during inevitable dips.", difficulty: "beginner", topic: "general", learnLink: "stocks" },
  { id: 106, question: "Why is it generally better to use a high-yield savings account for your emergency fund rather than investing it in stocks?", options: ["Stocks always lose money over short periods", "Emergency funds need to be liquid and stable — stock volatility could force you to sell at a loss precisely when you need cash most", "High-yield savings accounts always earn more than stocks", "There's no difference between the two options"], correct: 1, explanation: "Emergencies (job loss, medical bills) often coincide with economic downturns when stocks are declining. Needing to sell stocks at a 30% loss to cover expenses defeats the purpose. A HYSA provides instant access at a stable value.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 107, question: "The primary reason passive investing has grown from 3% to over 50% of fund assets since 1976 is:", options: ["Marketing by Vanguard", "Consistent empirical evidence that most active managers fail to justify their fees over long periods", "Government mandates requiring passive investing", "Active funds were made illegal"], correct: 1, explanation: "Decades of SPIVA data and academic research convinced investors that paying higher fees for active management usually results in worse outcomes. John Bogle's creation of the first index fund in 1976 started a revolution backed by overwhelming evidence.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 108, question: "A money market fund's NAV is typically maintained at $1.00. The event where it drops below $1.00 is called:", options: ["A market correction", "Breaking the buck — an extremely rare event that signals severe stress in short-term credit markets", "A dividend payment", "Normal daily fluctuation"], correct: 1, explanation: "Money market funds aim to maintain a $1 NAV. 'Breaking the buck' has happened only twice — most notably during the 2008 crisis when the Reserve Primary Fund dropped to $0.97. It triggered widespread panic and government intervention.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },
  { id: 109, question: "During the COVID crash of March 2020, the S&P 500 fell 34% in 23 trading days. Investors who sold at the bottom and waited for 'clarity' before reinvesting missed:", options: ["A modest 5% recovery", "A roughly 75% rally over the next 12 months — one of the fastest recoveries in history", "Nothing — the market continued falling for years", "A 10% recovery that took 5 years"], correct: 1, explanation: "The S&P 500 hit its COVID low on March 23, 2020 and recovered ALL losses by August 2020 — just 5 months. Investors who sold and waited for 'clarity' missed one of the most powerful rallies ever. The worst days and best days cluster together.", difficulty: "intermediate", topic: "dca", learnLink: "dca" },
  { id: 110, question: "The FIRE movement targets financial independence at 25× annual expenses. A couple spending $80,000/year needs:", options: ["$800,000", "$1,600,000", "$2,000,000", "$4,000,000"], correct: 2, explanation: "$80,000 × 25 = $2,000,000. This enables a 4% initial withdrawal rate. Many FIRE practitioners use a more conservative 3.5% rate (requiring ~29× expenses = $2.3M) since they may have 50+ year retirements instead of the 30 years the 4% rule was designed for.", difficulty: "intermediate", topic: "general", learnLink: "retirement" },
  { id: 111, question: "Company A has a P/B ratio of 0.7. This means:", options: ["The stock is overvalued", "The market values the company at less than the value of its net assets on the balance sheet — potentially undervalued or reflecting real problems", "The company has no assets", "The company's book value is negative"], correct: 1, explanation: "P/B < 1 means you can theoretically buy the company's assets at a 30% discount. But it could also signal that assets are impaired, earnings are declining, or the market sees problems not yet reflected in book value. Context matters.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 112, question: "An index fund manager reports a time-weighted return of 10%, but the average investor in the fund earned only 6% (dollar-weighted). What explains the gap?", options: ["The fund manager is lying", "Investors piled in after strong performance (buying high) and redeemed after declines (selling low), causing their personal returns to lag the fund's returns", "Dollar-weighted returns are calculated incorrectly", "The expense ratio consumed the difference"], correct: 1, explanation: "The 'behavior gap' (coined by Carl Richards) occurs because investors chase performance — adding money after rallies and withdrawing after declines. Morningstar consistently shows the average investor earns 1-4% less than the funds they invest in.", difficulty: "advanced", topic: "general", learnLink: "behavioral" },
  { id: 113, question: "A 5-year CD offers 4.5% APY while a 1-year CD offers 5.0% APY. This is unusual because:", options: ["Long-term CDs always offer higher rates", "An inverted rate structure (short-term > long-term) suggests the market expects interest rates to decline in the future", "The 1-year CD is riskier", "CD rates are set randomly by banks"], correct: 1, explanation: "Normally, longer terms pay higher rates to compensate for locking up money longer. When short-term rates exceed long-term rates, it signals expectations of falling rates ahead. This is the same concept as a yield curve inversion in Treasury markets.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 114, question: "A stock has a payout ratio of 95%. Its earnings just declined 10%. What is the dividend outlook?", options: ["The dividend will definitely increase next year", "The dividend is at high risk of being cut — a 95% payout ratio leaves almost no margin for earnings declines", "Payout ratio doesn't affect dividend sustainability", "The high payout ratio means the stock is a good income investment"], correct: 1, explanation: "A 95% payout ratio means the company distributes nearly all earnings as dividends. A 10% earnings decline pushes the payout over 100% (paying more than they earn), which is unsustainable. Companies in this position often cut dividends, causing sharp price drops.", difficulty: "intermediate", topic: "dividends", learnLink: "dividends" },
  { id: 115, question: "A robo-advisor charges 0.25% AUM plus the underlying ETF expense ratios averaging 0.05%. A human advisor charges 1% AUM. On $500,000 over 20 years at 8% growth, how much MORE does the human advisor cost?", options: ["About $15,000 total", "About $50,000 total", "About $150,000 in cumulative fee difference", "The costs are nearly identical"], correct: 2, explanation: "The 0.70% annual fee difference compounds over 20 years on a growing portfolio. The human advisor costs approximately $150,000+ more in cumulative fees. The question is whether personalized advice, behavioral coaching, and tax planning justify that premium.", difficulty: "advanced", topic: "general", learnLink: "index-funds" },
  { id: 116, question: "A SPAC IPOs at $10/share, announces a merger with a speculative tech company, and the stock rises to $25. After the merger closes, the stock falls to $7. This pattern is:", options: ["Unusual and unexpected", "Common — SPAC hype often drives pre-merger prices above fundamental value, followed by post-merger declines as speculation fades", "Evidence that SPACs are good investments", "Caused by market manipulation"], correct: 1, explanation: "This 'pop and drop' pattern is extremely common in SPACs. Pre-merger hype and low float drive prices up, but post-merger reality (actual earnings, dilution, and insider lockup expirations) typically disappoint. Academic studies show average SPACs significantly underperform.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 117, question: "An investor sees a stock drop 40% and says 'it just needs to go up 40% and I'll break even.' What's wrong with this math?", options: ["Nothing — 40% down then 40% up returns you to break-even", "A 40% loss requires a 67% gain to break even: $100 → $60 → $60 × 1.667 = $100. Larger losses need disproportionately larger recoveries.", "A 40% loss requires an 80% gain to break even", "Percentage losses and gains are always symmetrical"], correct: 1, explanation: "This is a critical math concept: $100 dropping 40% = $60. To get back to $100 from $60 requires a 67% gain ($40/$60). A 50% loss requires a 100% gain. A 75% loss requires a 300% gain. The asymmetry of losses is why capital preservation matters so much.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 118, question: "A stock is trading at its 52-week low. An investor concludes it's 'cheap.' Which analytical step is MISSING?", options: ["Checking if it's near its 52-week high instead", "Evaluating whether the low price reflects deteriorating fundamentals or whether the business value actually supports a higher price", "Nothing — 52-week lows are always buying opportunities", "Checking the stock's color on a chart"], correct: 1, explanation: "A 52-week low is a price data point, not a valuation metric. The stock could be at its low for good reason (declining earnings, losing market share) or bad reason (temporary fear). Without fundamental analysis, you're just anchoring to a historical price.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 119, question: "The S&P 500 represents approximately what percentage of total U.S. stock market capitalization?", options: ["About 50%", "About 65%", "About 80%", "100%"], correct: 2, explanation: "The S&P 500's ~500 stocks represent about 80% of U.S. market value. The remaining 20% is in mid-cap and small-cap stocks. This is why S&P 500 and total market fund returns are very similar, though total market provides slightly broader exposure.", difficulty: "beginner", topic: "index-funds", learnLink: "index-funds" },
  { id: 120, question: "A fund's prospectus reveals: 1.2% expense ratio, 5% front-end load, and 95% annual portfolio turnover. What is the most concerning number for a long-term investor?", options: ["The 5% front-end load (one-time cost)", "The 95% turnover (generating taxable short-term capital gains annually)", "The 1.2% expense ratio alone", "None — these are normal fund characteristics"], correct: 1, explanation: "While all three are bad, the 95% turnover is particularly damaging long-term. It generates frequent taxable distributions (often taxed as short-term gains at ordinary income rates) and increases transaction costs. Combined with the 1.2% ER, this fund faces enormous headwinds.", difficulty: "advanced", topic: "etfs", learnLink: "etfs" },
  { id: 121, question: "Value investing has historically outperformed growth investing over very long periods (50+ years). Why do many investors still prefer growth?", options: ["Value investing doesn't work anymore", "Growth stocks can dramatically outperform for 10+ year stretches (like 2010-2020), and recency bias causes investors to extrapolate recent trends", "Financial advisors never recommend value investing", "Growth investing has lower risk"], correct: 1, explanation: "Value's long-term outperformance ('value premium') can disappear for a decade or more. The 2010s saw extreme growth dominance, making value feel obsolete. But previous growth-dominant periods (1990s) were followed by value dominance (2000s). Factor premiums require patience.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 122, question: "I-Bonds purchased in a high-inflation environment (6%+ inflation) have what key limitation that investors should know?", options: ["They can lose principal value", "They're limited to $10,000 per person per year and cannot be sold for the first 12 months (with early redemption penalty in years 1-5)", "They have no limitations", "They can only be purchased through a broker"], correct: 1, explanation: "I-Bond limitations: $10K annual purchase limit, 12-month lockup, and 3-month interest penalty if redeemed before 5 years. They're excellent inflation hedges but illiquid and size-limited. They can only be purchased through TreasuryDirect.gov.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 123, question: "The 'buy and hold' strategy is psychologically difficult because:", options: ["It requires complex daily analysis", "Doing nothing during 30-50% market crashes requires extraordinary discipline, as every instinct screams 'sell'", "It doesn't work — active trading always outperforms", "Buying and holding means never rebalancing"], correct: 1, explanation: "Buy and hold sounds simple but is psychologically brutal. Watching $500K become $250K during a crash while headlines scream doom tests the strongest resolve. Studies show most investors abandon buy-and-hold at exactly the wrong time.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 124, question: "A HYSA offers 5% APY while the stock market has averaged 10% annually. Why not skip the emergency fund and invest that money instead?", options: ["You should — the stock market always returns more", "The emergency fund's purpose is stability when you need cash urgently; stocks can be down 30-50% at the exact moment you face an emergency, forcing you to sell at a loss", "HYSAs are always the better investment", "Emergency funds should be invested in bonds instead"], correct: 1, explanation: "Emergencies are unpredictable and often correlate with economic downturns (job loss during recession). Your emergency fund needs to be there at full value precisely when everything else is down. The 'cost' of lower returns is actually insurance against forced selling at a loss.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 125, question: "A company's free cash flow has declined for 3 consecutive years while its net income has grown. What might explain this divergence?", options: ["The company is becoming more profitable and the FCF decline is irrelevant", "Aggressive accounting (capitalizing expenses, relaxing receivables) can inflate net income while actual cash generation deteriorates — this is a potential red flag", "Free cash flow and net income always move in opposite directions", "The company is paying too many dividends"], correct: 1, explanation: "When earnings grow but cash flow shrinks, management may be using accounting techniques to make results look better than reality. Capitalizing expenses, stretching payables, or recognizing revenue aggressively can boost income without generating cash. Always check FCF.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 126, question: "Warren Buffett bet $1 million that an S&P 500 index fund would beat a basket of hedge funds over 10 years (2008-2017). What was the result?", options: ["The hedge funds won by a large margin", "Buffett's index fund returned 125.8% vs. the hedge funds' approximately 36% — the index fund won by a landslide", "They tied", "The bet was cancelled due to the 2008 crisis"], correct: 1, explanation: "Buffett's Vanguard S&P 500 fund returned 125.8% over the decade vs. roughly 36% for the basket of hedge funds selected by Protégé Partners. After fees ('2 and 20'), the hedge funds couldn't overcome their cost disadvantage despite supposedly superior strategies.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 127, question: "Two households earn $150,000/year. Family A saves 10%, Family B saves 40%. Assuming identical 8% investment returns, after 20 years:", options: ["They have similar net worth since they earn the same amount", "Family B has roughly 4× more invested wealth, AND can sustain their lifestyle on a smaller portfolio since their expenses are lower", "Family A is better off because they enjoy their money now", "Savings rate doesn't matter if returns are the same"], correct: 1, explanation: "Family A: $15K/year × 20 years at 8% ≈ $687K; needs $3.4M to replace income (at 4% rule). Family B: $60K/year × 20 years at 8% ≈ $2.7M; needs only $2.25M to replace expenses. Family B is wealthier AND closer to financial independence.", difficulty: "intermediate", topic: "general", learnLink: "retirement" },
  { id: 128, question: "Tax-deferred growth in a Traditional 401(k) means an investor in the 24% bracket who contributes $23,000 saves approximately how much in current-year taxes?", options: ["$0 — there's no immediate tax benefit", "$2,300", "$5,520 in reduced federal income tax", "$23,000"], correct: 2, explanation: "$23,000 × 24% = $5,520 immediate tax reduction. The contribution lowers your taxable income. You'll pay tax on withdrawals in retirement, but if your retirement tax rate is lower (common), you save the spread. Plus, the tax savings can be invested.", difficulty: "beginner", topic: "taxes", learnLink: "taxes" },
  { id: 129, question: "Benjamin Graham's 'margin of safety' principle most directly protects against:", options: ["Inflation risk only", "Errors in your analysis of intrinsic value, unforeseen negative events, and market irrationality", "Only stock market crashes", "Currency fluctuations"], correct: 1, explanation: "Margin of safety isn't about any single risk — it's a buffer against EVERYTHING that could go wrong: your valuation might be too optimistic, the company could face unexpected challenges, or the market could remain irrational. Buying at a discount protects against all of these.", difficulty: "advanced", topic: "general", learnLink: "stocks" },
  { id: 130, question: "If 90%+ of active funds underperform their benchmark over 15 years, how can an investor identify the winning 10% IN ADVANCE?", options: ["Choose funds with the highest past returns", "Look for the lowest expense ratios among active funds", "It's virtually impossible — past performance doesn't predict future results, which is the core argument for indexing", "Choose funds with the most assets"], correct: 2, explanation: "Research consistently shows that past winning funds rarely repeat. The few active funds that outperform one period are no more likely to outperform the next. Since you can't reliably identify winners in advance, indexing (guaranteeing the market return minus minimal fees) is the logical choice.", difficulty: "intermediate", topic: "index-funds", learnLink: "index-funds" },
  { id: 131, question: "Portfolio A: 100% stocks. Portfolio B: 80% stocks / 20% bonds. Over 30 years, Portfolio A has higher total returns. Why might Portfolio B still be the better choice?", options: ["Portfolio B is always worse because it has lower returns", "Portfolio B may produce better risk-adjusted returns (higher Sharpe ratio) with significantly less volatility, reducing the chance of panic selling during crashes", "Bonds always outperform stocks", "There's no rational reason to choose B"], correct: 1, explanation: "The risk-adjusted return often matters more than absolute return. A 100% stock portfolio might return 10% with 20% volatility, while 80/20 returns 9% with 12% volatility. The smoother ride of 80/20 makes it easier to stay invested — and actually capturing 9% beats theoretically earning 10% but panic-selling at -30%.", difficulty: "advanced", topic: "diversification", learnLink: "diversification" },
  { id: 132, question: "You can buy a traditional brokerage fund with a 0.8% expense ratio or a nearly identical Schwab/Fidelity fund at 0.02%. Over 30 years on $200,000 at 8% returns, the fee difference costs approximately:", options: ["About $5,000", "About $50,000", "About $200,000", "About $500,000"], correct: 2, explanation: "The 0.78% annual fee difference compounds devastatingly over 30 years. At 0.02%: ~$1.98M. At 0.8%: ~$1.78M. Difference: ~$200,000. This is why expense ratios are the best single predictor of fund performance — the lowest cost fund wins more often than not.", difficulty: "advanced", topic: "general", learnLink: "index-funds" },
  { id: 133, question: "The market hits new all-time highs. An investor says 'it's too high to invest now.' Historically, what happens after all-time highs?", options: ["Markets always crash after reaching new highs", "Markets hit new highs frequently during long-term uptrends — forward returns after all-time highs are statistically similar to returns from any other starting point", "You should always wait for a pullback before investing", "All-time highs guarantee above-average future returns"], correct: 1, explanation: "All-time highs are a normal feature of rising markets, not a warning sign. The S&P 500 has hit thousands of all-time highs throughout history. Research shows 1-year forward returns after all-time highs are roughly the same as returns from any other starting point.", difficulty: "intermediate", topic: "general", learnLink: "stocks" },
  { id: 134, question: "During a recession, which sectors have historically been MOST defensive (declining less than the market)?", options: ["Technology and consumer discretionary", "Consumer staples, healthcare, and utilities — companies whose products people need regardless of economic conditions", "Energy and financials", "Real estate and industrials"], correct: 1, explanation: "Defensive sectors sell necessities: food (staples), medicine (healthcare), electricity (utilities). Demand for these products is relatively inelastic — people buy toothpaste and take medications even in recessions. Cyclical sectors (tech, discretionary, industrials) are more sensitive to economic downturns.", difficulty: "intermediate", topic: "general", learnLink: "diversification" },
  { id: 135, question: "The 'wealth effect' can be dangerous because:", options: ["It always leads to wealth creation", "Rising asset values make people spend more and save less, increasing vulnerability to the inevitable downturn when paper wealth evaporates", "It only affects the ultra-wealthy", "There is no wealth effect in modern markets"], correct: 1, explanation: "When home values or portfolios rise, people feel richer and spend more (often on debt). When values inevitably correct, the spending habits remain but the wealth doesn't. This is how people end up house-rich and cash-poor, or overleveraged after market drops.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 136, question: "A 35-year-old has: $300K home equity, $50K in a 401(k), $15K in savings, $25K in car value, $200K mortgage, $30K student loans, and $5K credit card debt. Their net worth is:", options: ["$155,000", "$390,000", "$235,000", "$50,000"], correct: 0, explanation: "Assets: $300K + $50K + $15K + $25K = $390K. Liabilities: $200K + $30K + $5K = $235K. Net worth: $390K - $235K = $155,000. Many people overestimate their net worth by forgetting to subtract debts, or underestimate it by forgetting home equity.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 137, question: "Gold is often called an 'inflation hedge.' Over the last 50 years, which asset has actually provided better inflation protection?", options: ["Gold has been the best inflation hedge by far", "Cash and savings accounts", "A diversified stock portfolio has outpaced inflation more consistently, though gold has had periods of extreme outperformance", "Cryptocurrencies"], correct: 2, explanation: "Stocks have historically outpaced inflation by 7%+ annually over long periods. Gold has had spectacular short-term runs (1970s, 2010-2011, 2020+) but also decades-long stretches of flat or negative real returns. Stocks' compounding earnings make them a more reliable long-term inflation hedge.", difficulty: "advanced", topic: "general", learnLink: "diversification" },
  { id: 138, question: "The CAPE ratio (Shiller P/E) is currently 35, well above its historical average of 17. What should an investor conclude?", options: ["Sell everything immediately — a crash is imminent", "Expected long-term returns are likely below historical averages, but this is NOT a timing signal — high CAPE can persist for years", "Buy aggressively because high CAPE means strong earnings", "CAPE is obsolete and should be ignored"], correct: 1, explanation: "High CAPE correlates with lower 10-year forward returns, but it's a terrible timing tool. CAPE was 'elevated' from 2013 onward, yet stocks continued rising for over a decade. The correct response: temper return expectations but don't try to time the market based on CAPE alone.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 139, question: "A bond ladder with maturities of 1, 2, 3, 4, and 5 years provides which advantage over buying a single 5-year bond?", options: ["Higher total returns guaranteed", "Reduces interest rate risk by spreading maturities, provides regular liquidity as each bond matures, and allows reinvestment at current rates", "Eliminates all risk of loss", "It has no advantages"], correct: 1, explanation: "A ladder reduces reinvestment risk (you don't reinvest everything at one rate), provides liquidity (1/5 of your portfolio matures each year), and hedges interest rate risk (rising rates hurt short bonds less). It's a systematic approach to fixed-income investing.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 140, question: "Historically, $1 invested in U.S. stocks in 1926 would be worth approximately how much today (with dividends reinvested)?", options: ["About $100", "About $1,000", "About $12,000-$15,000", "About $100,000"], correct: 2, explanation: "Depending on the exact endpoint, $1 invested in 1926 in the S&P 500 with dividends reinvested has grown to roughly $12,000-$15,000. Without dividend reinvestment: roughly $250. This dramatic difference illustrates both the power of compounding and the importance of reinvesting dividends.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 141, question: "A preferred stock pays a $5 annual dividend and trades at $100. If interest rates rise and similar preferred stocks now yield 6%, this preferred stock's price will:", options: ["Rise to match the higher yield", "Stay at $100", "Fall to approximately $83.33 ($5 ÷ 0.06) to bring its yield in line with the market", "The dividend will increase to $6"], correct: 2, explanation: "Preferred stocks behave like bonds in this regard. With a fixed $5 dividend, the price must adjust to match market yields. At 6% yield: $5 ÷ 0.06 = $83.33. The ~17% price decline illustrates why preferred stocks carry significant interest rate risk.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 142, question: "A company's book value per share is $40, but the stock trades at $120 (P/B = 3.0). What might justify such a premium?", options: ["The company has excessive debt", "Strong intangible assets (brand, patents, network effects) and high return on equity that aren't fully reflected in book value", "Book value is always more accurate than market price", "The stock is definitely overvalued"], correct: 1, explanation: "Many modern companies (tech, pharma, consumer brands) have enormous intangible value not captured by book value. Apple's brand, Google's algorithms, and Visa's network are worth far more than their tangible assets. High P/B is justified when ROE is persistently above cost of equity.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 143, question: "Which statement about recessions is FALSE?", options: ["Recessions are commonly defined as two consecutive quarters of declining GDP", "The stock market typically begins recovering BEFORE the recession officially ends", "Recessions only occur once every 30-50 years", "Bear markets and recessions often overlap but are not the same thing"], correct: 2, explanation: "The U.S. has experienced 12 recessions since 1945 — roughly one every 6-7 years. They are a normal (if painful) part of the economic cycle. The stock market typically bottoms and begins recovering 6-9 months before the recession officially ends.", difficulty: "beginner", topic: "general", learnLink: "stocks" },
  { id: 144, question: "A stock yields 9% while the S&P 500 averages 1.5%. Before buying for the yield, what should you investigate FIRST?", options: ["Nothing — high yield is always good for income investors", "Whether the high yield is sustainable: check payout ratio, earnings trend, free cash flow coverage, and debt levels for signs of a potential dividend cut", "Whether the stock is included in the S&P 500", "The stock's 52-week high"], correct: 1, explanation: "An abnormally high yield (6×+ the market average) is often a 'yield trap.' The yield is high because the stock price has plummeted — possibly due to deteriorating fundamentals that will lead to a dividend cut. Companies like GE, Frontier Communications, and AT&T offered high yields right before cutting.", difficulty: "intermediate", topic: "dividends", learnLink: "dividends" },
  { id: 145, question: "VTI (Total U.S. Stock Market) holds ~4,000 stocks while VOO (S&P 500) holds ~500. Over the last 20 years, the performance difference has been:", options: ["VTI significantly outperformed due to small-cap exposure", "Extremely small (typically <0.5% annually) because the S&P 500 already captures ~80% of total market cap", "VOO dramatically outperformed because fewer stocks means higher quality", "They cannot be compared because they track different things"], correct: 1, explanation: "Since the S&P 500 represents ~80% of U.S. market cap, VTI and VOO have historically performed within a few tenths of a percent of each other. VTI adds small/mid-cap exposure but the weight is so small (~20%) that it barely moves the needle. Either is an excellent core holding.", difficulty: "intermediate", topic: "index-funds", learnLink: "index-funds" },
  { id: 146, question: "Which ordering MAXIMIZES the tax efficiency of your investment contributions?", options: ["Taxable brokerage → Roth IRA → 401(k)", "401(k) up to employer match → HSA → Roth IRA → 401(k) max → Taxable brokerage", "Roth IRA only — no other accounts needed", "It doesn't matter what order you contribute"], correct: 1, explanation: "The optimal order captures free money first (employer match), then maxes the triple-tax-advantaged HSA, then Roth IRA (tax-free growth), then fills remaining 401(k) space, and finally uses taxable accounts. This hierarchy maximizes tax efficiency at every level.", difficulty: "intermediate", topic: "taxes", learnLink: "taxes" },
  { id: 147, question: "A 30-year Treasury bond yields 4.5%. If inflation averages 3% over the next 30 years, the real (inflation-adjusted) return is approximately:", options: ["4.5%", "7.5%", "1.5%", "3%"], correct: 2, explanation: "Real return ≈ nominal yield - inflation = 4.5% - 3% = 1.5%. Over 30 years, a 1.5% real return barely grows your purchasing power. This is why bonds alone are insufficient for long-term wealth building — they protect capital but don't generate significant real growth.", difficulty: "beginner", topic: "bonds", learnLink: "bonds" },
  { id: 148, question: "During the 2021 meme stock frenzy, many new investors bought GameStop at $300+. Which THREE behavioral biases were most responsible?", options: ["Margin of safety, value investing, and patience", "FOMO, herd mentality, and overconfidence in the 'movement'", "Loss aversion, anchoring, and disposition effect", "Confirmation bias, sunk cost fallacy, and mental accounting"], correct: 1, explanation: "The meme stock mania was a textbook convergence of: FOMO (fear of missing the 'once in a lifetime' opportunity), herd mentality (following Reddit crowds), and overconfidence ('we can beat the hedge funds'). Most who bought above $200 suffered devastating losses.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 149, question: "$500/month invested at 10% annual return for 30 years grows to approximately $1.1 million. How much of that came from your actual contributions vs. compound growth?", options: ["$500K contributions, $600K growth", "$180,000 contributions, ~$920,000 from compound growth", "$550K contributions, $550K growth", "All $1.1M came from contributions"], correct: 1, explanation: "$500 × 12 months × 30 years = $180,000 in total contributions. The other ~$920,000 (84%) is pure compound growth — returns on returns on returns. This ratio illustrates why starting early matters: time is the ingredient that turns modest contributions into extraordinary wealth.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 150, question: "Which factor has the LARGEST impact on your long-term investment success?", options: ["Picking the right individual stocks", "Timing your entry and exit points perfectly", "Getting started early, investing consistently in low-cost diversified funds, and not panicking during downturns", "Having a high income"], correct: 2, explanation: "Academic research and decades of data point to the same conclusion: behavior (starting early, staying invested, keeping costs low) dominates stock-picking ability and market timing. A moderate earner who invests consistently from age 25 typically outweighs a high earner who starts at 40.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 151, question: "An immediate annuity provides guaranteed $2,000/month for life starting at age 65 in exchange for a $400,000 lump sum. What is the breakeven age?", options: ["About 72 years old", "About 82 years old ($400K ÷ $24K/year ≈ 16.7 years)", "About 90 years old", "You never break even — annuities always lose money"], correct: 1, explanation: "$24,000/year × 16.7 years = $400,000. Breakeven is around age 82. If you live past 82, the annuity wins. If you die before, you 'lose.' This is longevity insurance — valuable if you fear outliving your money but comes at the cost of liquidity and legacy.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 152, question: "A SIMPLE IRA requires employer contributions. What is the MINIMUM an employer must provide?", options: ["Nothing — employer contributions are optional", "Either a dollar-for-dollar match up to 3% of compensation, OR a flat 2% contribution to all eligible employees", "A 50% match up to 6%", "10% of each employee's salary"], correct: 1, explanation: "SIMPLE IRAs mandate employer contributions (unlike 401ks where matching is optional). The employer must either match employee contributions dollar-for-dollar up to 3% OR contribute 2% of every eligible employee's pay regardless of whether they contribute.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 153, question: "Peter Lynch's GARP strategy uses the PEG ratio (P/E ÷ earnings growth rate). A stock with a P/E of 25 and earnings growth of 30% has a PEG of:", options: ["0.83 — potentially undervalued (PEG < 1)", "1.2 — fairly valued", "25 — the P/E is the PEG", "55 — add P/E and growth rate"], correct: 0, explanation: "PEG = P/E ÷ growth rate = 25 ÷ 30 = 0.83. A PEG below 1 suggests the stock's growth rate justifies its P/E. A PEG above 1 suggests the stock may be expensive relative to its growth. Peter Lynch popularized this metric as a quick growth-at-a-reasonable-price screen.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 154, question: "Warren Buffett says Coca-Cola has a 'wide moat.' What is the PRIMARY source of that moat?", options: ["Low production costs", "Patent protection on the Coca-Cola formula", "Brand power and global distribution — creating extraordinary customer loyalty and barriers to entry that have persisted for 130+ years", "Government regulation preventing competition"], correct: 2, explanation: "Coca-Cola's moat is its brand and distribution network. The formula matters less than the fact that 'Coca-Cola' is the second most recognized word on Earth. No competitor can replicate 130 years of brand building and distribution infrastructure, regardless of how much they spend.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 155, question: "A stock's dividend yield is 5.5% but its payout ratio is 110%. What does a payout ratio above 100% specifically mean?", options: ["The company is growing faster than expected", "The company is paying out more in dividends than it earns — financing dividends with debt or reserves, which is unsustainable long-term", "The dividend will increase next quarter", "The yield is calculated incorrectly"], correct: 1, explanation: "A payout ratio above 100% means dividends exceed earnings. The company is either borrowing, using reserves, or selling assets to fund the dividend. This is a major red flag — such situations almost always end in a dividend cut. The high yield is a trap.", difficulty: "intermediate", topic: "dividends", learnLink: "dividends" },
];
